import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import {
  SummaryBlock,
  Highlight,
} from '../../models/analytics-dashboard.interface';

@Component({
  selector: 'app-summary-block',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './summary-block.component.html',
  styleUrls: ['./summary-block.component.scss'],
})
export class SummaryBlockComponent {
  @Input() block!: SummaryBlock;

  getThemeClass(): string {
    if (this.block.visual?.theme) {
      return `theme-${this.block.visual.theme}`;
    }
    return 'theme-primary';
  }

  getHighlightClass(highlight: Highlight): string[] {
    const classes = [`severity-${highlight.severity}`];

    if (highlight.trend) {
      classes.push(`trend-${highlight.trend}`);
    }

    return classes;
  }

  getTrendIcon(trend: string): string {
    switch (trend) {
      case 'up':
        return 'trend-up';
      case 'down':
        return 'trend-down';
      case 'stable':
        return 'trend-stable';
      default:
        return '';
    }
  }
}
