import { Injectable, inject } from '@angular/core';
import {
  HttpClient,
  HttpHeaders,
  HttpErrorResponse,
} from '@angular/common/http';
import { BehaviorSubject } from 'rxjs';
import {
  DataCollectionRequest,
  DataCollectionResult,
  DateChunk,
  CollectionProgress,
  AggregatedData,
  DataType,
  TelemetryApiResponse,
  TripItem,
  EventItem,
  TelemetryItem,
  AlertItem,
  CollectionError,
} from '../interfaces/telemetry-data-collector.interface';
import { isDefined, isNullOrUndefined } from '../../shared/utils';

@Injectable({
  providedIn: 'root',
})
export class TelemetryDataCollectionService {
  private readonly http = inject(HttpClient);

  private readonly MAX_CONCURRENT_REQUESTS = 10;
  private readonly MAX_RETRY_ATTEMPTS = 3;
  private readonly RETRY_DELAY_BASE = 1000; // 1 second
  private readonly HOURS_24_MS = 24 * 60 * 60 * 1000;

  private readonly progressSubject = new BehaviorSubject<CollectionProgress>({
    totalRequests: 0,
    completedRequests: 0,
    successfulRequests: 0,
    failedRequests: 0,
    percentage: 0,
    message: 'Initializing data collection...',
  });

  public progress$ = this.progressSubject.asObservable();

  splitInto24HourChunks(startDate: string, endDate: string): DateChunk[] {
    const chunks: DateChunk[] = [];
    const start = new Date(startDate);
    const end = new Date(endDate);

    let currentStart = new Date(start);
    while (currentStart < end) {
      const currentEnd = new Date(
        Math.min(currentStart.getTime() + this.HOURS_24_MS, end.getTime()),
      );

      chunks.push({
        start: currentStart.toISOString(),
        end: currentEnd.toISOString(),
      });

      currentStart = new Date(currentEnd);
    }

    return chunks;
  }

  private createHeaders(authToken: string): HttpHeaders {
    return new HttpHeaders({
      'x-access-token': authToken,
      'Content-Type': 'application/json',
      Accept: 'application/json',
    });
  }

  private buildApiUrl(
    baseUrl: string,
    dataType: DataType,
    vehicleId: string,
    start: string,
    end: string,
  ): string {
    const endpoint = `${baseUrl}/data/history/${dataType}/${vehicleId}`;
    const params = new URLSearchParams({
      start,
      end,
    });
    return `${endpoint}?${params.toString()}`;
  }

  private async collectVehicleData(
    dataType: DataType,
    vehicleId: string,
    chunk: DateChunk,
    baseUrl: string,
    authToken: string,
    retryCount = 0,
  ): Promise<{
    dataType: DataType;
    vehicleId: string;
    data: TelemetryApiResponse;
    chunk: DateChunk;
  }> {
    const headers = this.createHeaders(authToken);
    const url = this.buildApiUrl(
      baseUrl,
      dataType,
      vehicleId,
      chunk.start,
      chunk.end,
    );

    try {
      const response = await this.http
        .get<TelemetryApiResponse>(url, { headers })
        .toPromise();

      if (!response) {
        throw new Error('No response received from API');
      }

      return {
        dataType,
        vehicleId,
        data: response,
        chunk,
      };
    } catch (error) {
      const httpError = error as HttpErrorResponse;

      // Handle authentication errors (don't retry)
      if (httpError.status === 401 || httpError.status === 403) {
        throw new Error('Authentication failed. Please provide a valid token.');
      }

      // Handle rate limiting with exponential backoff
      if (httpError.status === 429 && retryCount < this.MAX_RETRY_ATTEMPTS) {
        const delay = Math.pow(2, retryCount) * this.RETRY_DELAY_BASE;

        await new Promise((resolve) => setTimeout(resolve, delay));
        return this.collectVehicleData(
          dataType,
          vehicleId,
          chunk,
          baseUrl,
          authToken,
          retryCount + 1,
        );
      }

      // For other errors, throw with context
      throw new Error(
        `Failed to collect ${dataType} data for vehicle ${vehicleId}: ${httpError.message || 'Unknown error'}`,
      );
    }
  }

  private updateProgress(update: Partial<CollectionProgress>): void {
    const current = this.progressSubject.value;
    const newProgress: CollectionProgress = {
      ...current,
      ...update,
    };

    // Calculate percentage based on current totals
    const totalRequests = newProgress.totalRequests;
    const completedRequests = newProgress.completedRequests;

    if (totalRequests > 0) {
      newProgress.percentage = Math.round(
        (completedRequests / totalRequests) * 100,
      );
    }

    this.progressSubject.next(newProgress);
  }

  private aggregateResults(
    results: {
      dataType: DataType;
      vehicleId: string;
      data: TelemetryApiResponse;
      chunk: DateChunk;
    }[],
    errors: CollectionError[],
    request: DataCollectionRequest,
  ): AggregatedData {
    const aggregated: AggregatedData = {
      vehicles: {},
      metadata: {
        start_date: request.startDate,
        end_date: request.endDate,
        vehicle_count: request.vehicleIds.length,
        data_types: request.dataTypes,
        collection_timestamp: new Date().toISOString(),
        successful_requests: results.length,
        failed_requests: errors.length,
        total_requests: results.length + errors.length,
        timezone: 'Africa/Johannesburg',
        business_context: {
          fleet_type: 'delivery',
          region: 'south_africa',
          kpi_focus: ['efficiency', 'safety', 'fuel_consumption'],
        },
      },
    };

    // Create a map from vehicleId to vehicleName for easy lookup
    const idToNameMap: Record<string, string> = request.vehicleNames ?? {};

    // Initialize vehicle structures using vehicle NAME as the key
    request.vehicleIds.forEach((vehicleId) => {
      const vehicleName = idToNameMap[vehicleId] || vehicleId;
      aggregated.vehicles[vehicleName] = {
        vehicle_info: {
          id: vehicleId,
          name: vehicleName,
          active: true,
        },
        trips: [],
        events: [],
        telemetry: [],
        alerts: [],
        data_summary: {
          trip_count: 0,
          event_count: 0,
          telemetry_count: 0,
          alert_count: 0,
          date_range: { earliest: null, latest: null },
        },
      };
    });

    // Process results and organize by vehicle
    results.forEach((result) => {
      if (isDefined(result.data?.items) && Array.isArray(result.data.items)) {
        const { dataType, vehicleId } = result;
        const items = result.data.items;

        // Look up vehicle name from ID
        const vehicleName = idToNameMap[vehicleId] || vehicleId;

        if (isDefined(aggregated.vehicles[vehicleName])) {
          // Add data to the specific vehicle
          switch (dataType) {
            case 'trips':
              aggregated.vehicles[vehicleName].trips.push(
                ...(items as TripItem[]),
              );
              break;
            case 'events':
              aggregated.vehicles[vehicleName].events.push(
                ...(items as EventItem[]),
              );
              break;
            case 'telemetry':
              aggregated.vehicles[vehicleName].telemetry.push(
                ...(items as TelemetryItem[]),
              );
              break;
            case 'alerts':
              aggregated.vehicles[vehicleName].alerts.push(
                ...(items as AlertItem[]),
              );
              break;
          }

          // Update vehicle summary
          const vehicleData = aggregated.vehicles[vehicleName];
          vehicleData.data_summary.trip_count = vehicleData.trips.length;
          vehicleData.data_summary.event_count = vehicleData.events.length;
          vehicleData.data_summary.telemetry_count =
            vehicleData.telemetry.length;
          vehicleData.data_summary.alert_count = vehicleData.alerts.length;

          // Update date ranges from trip data
          if (dataType === 'trips') {
            vehicleData.trips.forEach((trip) => {
              const startDate = trip.startTime;
              if (startDate) {
                const summary = vehicleData.data_summary;
                if (
                  isNullOrUndefined(summary.date_range.earliest) ||
                  startDate < summary.date_range.earliest
                ) {
                  summary.date_range.earliest = startDate;
                }
                if (
                  isNullOrUndefined(summary.date_range.latest) ||
                  startDate > summary.date_range.latest
                ) {
                  summary.date_range.latest = startDate;
                }
              }
            });
          }
        }
      }
    });

    return aggregated;
  }

  async collectFleetData(
    request: DataCollectionRequest,
  ): Promise<DataCollectionResult> {
    try {
      // Validate request
      if (!request.vehicleIds.length) {
        throw new Error('At least one vehicle ID is required');
      }

      if (!request.dataTypes.length) {
        throw new Error('At least one data type is required');
      }

      // Check date range (max 7 days)
      const startTime = new Date(request.startDate).getTime();
      const endTime = new Date(request.endDate).getTime();
      const daysDiff = (endTime - startTime) / (24 * 60 * 60 * 1000);

      if (daysDiff > 7) {
        throw new Error(
          'Date range cannot exceed 7 days for performance reasons',
        );
      }

      // Split into 24-hour chunks
      const dateChunks = this.splitInto24HourChunks(
        request.startDate,
        request.endDate,
      );

      // Calculate total requests
      const totalRequests =
        dateChunks.length *
        request.vehicleIds.length *
        request.dataTypes.length;

      // Initialize progress
      this.updateProgress({
        totalRequests,
        completedRequests: 0,
        successfulRequests: 0,
        failedRequests: 0,
        message: `Preparing to collect data from ${request.vehicleIds.length} vehicles...`,
      });

      // Create all collection tasks
      const collectionTasks: (() => Promise<{
        dataType: DataType;
        vehicleId: string;
        data: TelemetryApiResponse;
        chunk: DateChunk;
      }>)[] = [];

      for (const chunk of dateChunks) {
        for (const vehicleId of request.vehicleIds) {
          for (const dataType of request.dataTypes) {
            collectionTasks.push(() =>
              this.collectVehicleData(
                dataType,
                vehicleId,
                chunk,
                request.baseUrl,
                request.authToken,
              ),
            );
          }
        }
      }

      // Execute tasks with limited concurrency
      const results: {
        dataType: DataType;
        vehicleId: string;
        data: TelemetryApiResponse;
        chunk: DateChunk;
      }[] = [];
      const errors: CollectionError[] = [];

      // Process in batches of MAX_CONCURRENT_REQUESTS
      for (
        let i = 0;
        i < collectionTasks.length;
        i += this.MAX_CONCURRENT_REQUESTS
      ) {
        const batch = collectionTasks.slice(
          i,
          i + this.MAX_CONCURRENT_REQUESTS,
        );

        const batchResults = await Promise.allSettled(
          batch.map((task) => task()),
        );

        batchResults.forEach((result, index) => {
          const globalIndex = i + index;

          // Calculate the correct indices based on the task structure:
          // For each chunk -> for each vehicle -> for each data type
          const vehiclesPerChunk = request.vehicleIds.length;
          const dataTypesPerVehicle = request.dataTypes.length;
          const tasksPerChunk = vehiclesPerChunk * dataTypesPerVehicle;

          const chunkIndex = Math.floor(globalIndex / tasksPerChunk);
          const taskInChunk = globalIndex % tasksPerChunk;
          const vehicleIndex = Math.floor(taskInChunk / dataTypesPerVehicle);
          const dataTypeIndex = taskInChunk % dataTypesPerVehicle;

          const vehicleId = request.vehicleIds[vehicleIndex];
          const dataType = request.dataTypes[dataTypeIndex];

          if (result.status === 'fulfilled') {
            results.push(result.value);
            this.updateProgress({
              completedRequests: results.length + errors.length,
              successfulRequests: results.length,
              currentVehicle: vehicleId,
              currentDataType: dataType,
              message: `Collected ${dataType} data for ${vehicleId}...`,
            });
          } else {
            errors.push({
              vehicleId,
              dataType,
              dateChunk: dateChunks[chunkIndex],
              error: result.reason?.message ?? 'Unknown error',
              statusCode: result.reason?.status,
              retryCount: 0,
            });

            this.updateProgress({
              completedRequests: results.length + errors.length,
              failedRequests: errors.length,
              currentVehicle: vehicleId,
              currentDataType: dataType,
              message: `Failed to collect ${dataType} data for ${vehicleId}`,
            });
          }
        });

        // Small delay between batches to avoid overwhelming the API
        if (i + this.MAX_CONCURRENT_REQUESTS < collectionTasks.length) {
          await new Promise((resolve) => setTimeout(resolve, 100));
        }
      }

      // Final progress update
      this.updateProgress({
        message: 'Aggregating collected data...',
      });

      // Aggregate results
      const aggregatedData = this.aggregateResults(results, errors, request);

      // Final progress update
      this.updateProgress({
        message: `Collection complete! Gathered ${results.length} successful responses${errors.length > 0 ? ` with ${errors.length} errors` : ''}`,
      });

      return {
        success: errors.length === 0 || results.length > 0,
        data: aggregatedData,
        errors: errors.length > 0 ? errors : undefined,
        progress: this.progressSubject.value,
      };
    } catch (error) {
      const errorMessage =
        error instanceof Error
          ? error.message
          : 'Unknown error occurred during data collection';

      this.updateProgress({
        message: `Collection failed: ${errorMessage}`,
      });

      return {
        success: false,
        errors: [
          {
            vehicleId: 'unknown',
            dataType: 'trips' as DataType,
            dateChunk: { start: request.startDate, end: request.endDate },
            error: errorMessage,
            retryCount: 0,
          },
        ],
        progress: this.progressSubject.value,
      };
    }
  }

  resetProgress(): void {
    this.progressSubject.next({
      totalRequests: 0,
      completedRequests: 0,
      successfulRequests: 0,
      failedRequests: 0,
      percentage: 0,
      message: 'Ready to collect data...',
    });
  }
}
