  // Helper method to safely convert values to strings
  private safeStringify(value: unknown): string {
    if (value === null || value === undefined) {
      return '';
    }
    if (typeof value === 'string') {
      return value;
    }
    if (typeof value === 'number' || typeof value === 'boolean') {
      return String(value);
    }
    if (typeof value === 'object') {
      try {
        return JSON.stringify(value);
      } catch {
        return '[Object]';
      }
    }
    // Handle symbols, functions, bigint, etc.
    if (typeof value === 'function') {
      return '[Function]';
    }
    if (typeof value === 'symbol') {
      return value.toString();
    }
    if (typeof value === 'bigint') {
      return value.toString();
    }
    return '[Unknown]';
  }

  readonly selectedAssetNames = computed(() => {
    const assetIds = this._selectedAssetIds();
    const allAssets = this.assets();

    if (!Array.isArray(allAssets) || !Array.isArray(assetIds)) {
      return 'Loading...';
    }

    const selectedAssets = allAssets.filter(
      (asset) => isDefined(asset?.value) && assetIds.includes(asset.value),
    );

    if (selectedAssets.length === 0) {
      return 'No vehicles selected';
    }

    return selectedAssets
      .map((asset) =>
        this.safeStringify(asset.label || asset.value || 'Unknown Vehicle'),
      )
      .join(', ');
  });

  readonly isMultipleVehiclesSelected = computed(() => {
    return this._selectedAssetIds().length > 1;
  });

  readonly isDateRangeGreaterThan2Days = computed(() => {
    const startDate = this.apiForm.get('startDate')?.value;
    const endDate = this.apiForm.get('endDate')?.value;

    if (isNullOrUndefined(startDate) || isNullOrUndefined(endDate)) {
      return false;
    }

    const start = new Date(startDate);
    const end = new Date(endDate);
    const diffInMs = end.getTime() - start.getTime();
    const diffInDays = diffInMs / (1000 * 60 * 60 * 24);

    return diffInDays > 2;
  });

  readonly shouldDisableTelemetry = computed(() => {
    return (
      this.isMultipleVehiclesSelected() && this.isDateRangeGreaterThan2Days()
    );
  });

  readonly reportSummary = computed(() => {
    const response = this.apiResponse();
    const analyticsData = response?.data as AnalyticsResponse | undefined;
    const summary = analyticsData?.response?.summary;
    return this.safeStringify(summary) || 'Report generated successfully.';
  });

  readonly formatDateRange = computed(() => {
    const startDate = this.apiForm.get('startDate')?.value;
    const endDate = this.apiForm.get('endDate')?.value;

    if (isNullOrUndefined(startDate) || isNullOrUndefined(endDate)) {
      return 'Date range not selected';
    }

    try {
      const formatDate = (date: string | number | Date) => {
        if (isNullOrUndefined(date)) return 'Invalid Date';
        const d = new Date(date);
        return d.toLocaleDateString('en-US', {
          month: 'short',
          day: 'numeric',
          year: 'numeric',
          hour: 'numeric',
          minute: '2-digit',
          hour12: true,
        });
      };

      return `${formatDate(startDate)} - ${formatDate(endDate)}`;
    } catch {
      return 'Invalid date range';
    }
  });

