import { Component, Input } from '@angular/core';
import { CommonModule } from '@angular/common';
import {
  TableBlock,
  AggregationType,
  ColumnSummaryConfig,
} from '../../models/analytics-dashboard.interface';
import { isNullOrUndefined } from '../../../../../../../shared/utils';

interface SortState {
  column: number;
  direction: 'asc' | 'desc';
}

@Component({
  selector: 'app-table-block',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './table-block.component.html',
  styleUrls: ['./table-block.component.scss'],
})
export class TableBlockComponent {
  @Input() block!: TableBlock;

  sortState: SortState = { column: -1, direction: 'asc' };
  isFullscreen = false;
  hoveredRow = -1;

  get showSummary(): boolean {
    return this.block.content.summary?.enabled ?? true;
  }

  trackByRow(index: number, row: (string | number)[]): string {
    return `row-${index}-${row.join('-')}`;
  }

  getBlockClasses(): string[] {
    const classes = ['table-block'];

    if (this.block.visual?.theme) {
      classes.push(`theme-${this.block.visual.theme}`);
    }

    return classes;
  }

  get sortedRows(): (string | number)[][] {
    const rows = this.block.content.rows;
    if (!Array.isArray(rows) || rows.length === 0) {
      return [];
    }

    if (
      this.sortState.column === -1 ||
      isNullOrUndefined(this.block.content.sortable)
    ) {
      return rows;
    }

    return [...rows].sort((a, b) => {
      const aVal = a[this.sortState.column];
      const bVal = b[this.sortState.column];

      const modifier = this.sortState.direction === 'asc' ? 1 : -1;

      if (typeof aVal === 'number' && typeof bVal === 'number') {
        return (aVal - bVal) * modifier;
      }

      return String(aVal).localeCompare(String(bVal)) * modifier;
    });
  }

  sortColumn(columnIndex: number): void {
    if (isNullOrUndefined(this.block.content.sortable)) return;

    if (this.sortState.column === columnIndex) {
      this.sortState.direction =
        this.sortState.direction === 'asc' ? 'desc' : 'asc';
    } else {
      this.sortState.column = columnIndex;
      this.sortState.direction = 'asc';
    }
  }

  getSortIcon(columnIndex: number): string {
    if (this.sortState.column !== columnIndex) {
      return 'sort-none';
    }
    return this.sortState.direction === 'asc' ? 'sort-asc' : 'sort-desc';
  }

  getSortAttribute(columnIndex: number): string | null {
    if (
      this.sortState.column !== columnIndex ||
      isNullOrUndefined(this.block.content.sortable)
    ) {
      return null;
    }
    return this.sortState.direction === 'asc' ? 'ascending' : 'descending';
  }

  formatCell(cell: string | number, columnIndex: number): string {
    if (typeof cell === 'number') {
      const header = this.block.content.headers[columnIndex].toLowerCase();

      if (header.includes('percent') || header.includes('%')) {
        return `${cell.toFixed(1)}%`;
      }
      if (header.includes('distance') || header.includes('km')) {
        return `${cell.toLocaleString()} km`;
      }
      if (
        header.includes('currency') ||
        header.includes('cost') ||
        header.includes('price')
      ) {
        return new Intl.NumberFormat('en-ZA', {
          style: 'currency',
          currency: 'ZAR',
          minimumFractionDigits: 0,
        }).format(cell);
      }
      if (header.includes('duration') || header.includes('time')) {
        const hours = Math.floor(cell / 60);
        const minutes = cell % 60;
        if (hours > 0) {
          return `${hours}h ${minutes}m`;
        }
        return `${minutes}m`;
      }

      return cell.toLocaleString();
    }

    return String(cell);
  }

  isNumeric(value: string | number): boolean {
    return typeof value === 'number';
  }

  getCellTooltip(cell: string | number, columnIndex: number): string {
    const header = this.block.content.headers[columnIndex];
    return `${header}: ${this.formatCell(cell, columnIndex)}`;
  }

  shouldShowTrend(cell: string | number, columnIndex: number): boolean {
    // Only show trends for numeric columns with percentage or change indicators
    return (
      typeof cell === 'number' &&
      (this.block.content.headers[columnIndex]
        .toLowerCase()
        .includes('change') ||
        this.block.content.headers[columnIndex]
          .toLowerCase()
          .includes('growth'))
    );
  }

  getTrendClass(cell: string | number): string {
    if (typeof cell !== 'number') return 'trend-neutral';

    if (cell > 0) return 'trend-positive';
    if (cell < 0) return 'trend-negative';
    return 'trend-neutral';
  }

  getTrendIndicator(cell: string | number): string {
    if (typeof cell !== 'number') return '';

    if (cell > 0) return '↗';
    if (cell < 0) return '↘';
    return '→';
  }

  onRowHover(rowIndex: number): void {
    this.hoveredRow = rowIndex;
  }

  onRowLeave(): void {
    this.hoveredRow = -1;
  }

  getSummaryStats(): { label: string; value: string }[] {
    const rows = this.sortedRows;
    if (rows.length === 0) return [];

    const stats: { label: string; value: string }[] = [
      { label: 'Records', value: rows.length.toString() },
    ];

    // Check if summary is explicitly disabled
    if (this.block.content.summary?.enabled === false) {
      return stats;
    }

    // Get columns to summarize
    const columnsToSummarize = this.getColumnsToSummarize();

    // Calculate aggregations for each configured column
    for (const config of columnsToSummarize) {
      const header = this.block.content.headers[config.column_index];
      const values = rows
        .map((row) => row[config.column_index])
        .filter((val): val is number => typeof val === 'number');

      if (values.length === 0) continue;

      const format =
        config.format ?? this.detectColumnFormat(config.column_index);
      const columnLabel = config.label ?? header;

      for (const aggType of config.aggregations) {
        const aggValue = this.calculateAggregation(values, aggType);
        const formattedValue = this.formatAggregationValue(aggValue, format);
        const aggLabel = this.getAggregationLabel(aggType, columnLabel);

        stats.push({ label: aggLabel, value: formattedValue });
      }
    }

    return stats;
  }

  private getColumnsToSummarize(): ColumnSummaryConfig[] {
    // If explicitly configured, use that
    if (
      this.block.content.summary?.columns !== undefined &&
      this.block.content.summary.columns.length > 0
    ) {
      return this.block.content.summary.columns;
    }

    // Otherwise, return empty array to show only record count
    // This prevents misleading automatic aggregations on unknown column types
    return [];
  }

  private calculateAggregation(
    values: number[],
    type: AggregationType,
  ): number {
    if (values.length === 0) return 0;

    switch (type) {
      case 'count':
        return values.length;
      case 'sum':
        return values.reduce((acc, val) => acc + val, 0);
      case 'average':
        return values.reduce((acc, val) => acc + val, 0) / values.length;
      case 'min':
        return Math.min(...values);
      case 'max':
        return Math.max(...values);
      case 'median': {
        const sorted = [...values].sort((a, b) => a - b);
        const mid = Math.floor(sorted.length / 2);
        return sorted.length % 2 === 0
          ? (sorted[mid - 1] + sorted[mid]) / 2
          : sorted[mid];
      }
      default:
        return 0;
    }
  }

  private formatAggregationValue(
    value: number,
    format: 'number' | 'percentage' | 'currency' | 'duration',
  ): string {
    switch (format) {
      case 'percentage':
        return `${value.toFixed(1)}%`;
      case 'currency':
        return new Intl.NumberFormat('en-ZA', {
          style: 'currency',
          currency: 'ZAR',
          minimumFractionDigits: 0,
        }).format(value);
      case 'duration': {
        const hours = Math.floor(value / 60);
        const minutes = Math.round(value % 60);
        if (hours > 0) {
          return `${hours}h ${minutes}m`;
        }
        return `${minutes}m`;
      }
      case 'number':
      default:
        return value.toLocaleString(undefined, {
          minimumFractionDigits: 0,
          maximumFractionDigits: 2,
        });
    }
  }

  private getAggregationLabel(
    type: AggregationType,
    columnLabel: string,
  ): string {
    switch (type) {
      case 'count':
        return `${columnLabel} Count`;
      case 'sum':
        return `${columnLabel} Total`;
      case 'average':
        return `${columnLabel} Avg`;
      case 'min':
        return `${columnLabel} Min`;
      case 'max':
        return `${columnLabel} Max`;
      case 'median':
        return `${columnLabel} Median`;
      default:
        return columnLabel;
    }
  }

  private detectColumnFormat(
    columnIndex: number,
  ): 'number' | 'percentage' | 'currency' | 'duration' {
    const header = this.block.content.headers[columnIndex].toLowerCase();

    if (header.includes('percent') || header.includes('%')) {
      return 'percentage';
    }
    if (
      header.includes('currency') ||
      header.includes('cost') ||
      header.includes('price')
    ) {
      return 'currency';
    }
    if (header.includes('duration') || header.includes('time')) {
      return 'duration';
    }

    return 'number';
  }

  private isProbablyIdColumn(columnIndex: number): boolean {
    const header = this.block.content.headers[columnIndex].toLowerCase();
    return (
      header.includes('id') ||
      header.includes('number') ||
      header.includes('code') ||
      header === '#'
    );
  }

  toggleFullscreen(): void {
    this.isFullscreen = !this.isFullscreen;
  }

  exportTable(): void {
    const headers = this.block.content.headers.join(',');
    const rows = this.sortedRows
      .map((row) => row.map((cell) => `"${cell}"`).join(','))
      .join('\n');

    const csv = `${headers}\n${rows}`;
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = globalThis.URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `${this.block.content.title ?? 'table-data'}.csv`;
    link.click();

    globalThis.URL.revokeObjectURL(url);
  }
}
